// Create your variables here
var score = 0;
var scorex = 0;
var scorey = 0;
var floor = createSprite(200, 200);
floor.setAnimation("floorfront");
//monsters
var runner = createSprite(400, 125);
runner.setAnimation("runner");
runner.scale = 2;
runner.visible = 76;
var crawler = createSprite(400, 125);
crawler.setAnimation("crawler");
crawler.scale = 2;
crawler.velocityX = 0;
crawler.visible = 0;
//background
var wall = createSprite(200, 200);
wall.setAnimation("wallfront");
var curtain = createSprite(200, 200);
curtain.setAnimation("curtain");
curtain.setCollider("rectangle", -80, -90, 50, 150);
var bookshelf = createSprite(200, 150);
bookshelf.setAnimation("Bookshelf");
var table = createSprite(200, 200);
table.setAnimation("table");
var talkie = createSprite(200, 200);
talkie.setAnimation("walkietalkie");
var hands = createSprite(200, 350);
hands.setAnimation("hands");
hands.scale = 1.25;
var door = createSprite(200, 200);
door.setAnimation("door");
door.visible = 0;
var heart = createSprite(300, 200);
heart.setAnimation("heart");
heart.visible = 0;
heart.scale = 0.4;
var lump = createSprite(220, 165);
lump.setAnimation("lump");
lump.visible = 0;
var light = createSprite(200, 200);
light.setAnimation("light");
var dead = createSprite(200, 200);
dead.setAnimation("dead");
dead.visible = 0;
var start = createSprite(200, 200);
start.setAnimation("animation_1");
function leftroom() {
  scorex = 350;
  scorey = 360;
  talkie.visible = 0;
  curtain.visible = 0;
  door.visible = 100;
  lump.visible = 0;
  heart.visible = 0;
  bookshelf.visible = 100;
  floor.setAnimation("leftfloor");
  wall.setAnimation("leftwall");
  bookshelf.setAnimation("leftbookshelf");
  table.setAnimation("lefttable");
  hands.setAnimation("lefthand");
}
function rightroom() {
  scorex = 500;
  scorey = 500;
  fill("black");
  rect(250, 150, 200, 200);
  talkie.visible = 0;
  door.visible = 0;
  lump.visible = 100;
  heart.visible = 100;
  curtain.visible = 0;
  bookshelf.visible = 0;
  floor.setAnimation("rightfloor");
  wall.setAnimation("rightwall");
  table.setAnimation("righttable");
  hands.setAnimation("Righthand");
}
function frontroom() {
  scorex = 25;
  scorey = 285;
  runner.velocityX = randomNumber(-4, -6);
  talkie.visible = 100;
  door.visible = 0;
  lump.visible = 0;
  heart.visible = 0;
  curtain.visible = 100;
  bookshelf.visible = 100;
  floor.setAnimation("floorfront");
  wall.setAnimation("wallfront");
  bookshelf.setAnimation("Bookshelf");
  table.setAnimation("table");
  hands.setAnimation("hands");
}

// Create your sprites here

function draw() {
  // draw background
  background(rgb(88, 94, 138));
  if (keyWentDown("space")) {
    start.visible = 0;
    runner.velocityX = randomNumber(-4, -6);
    scorex = 25;
    scorey = 285;
  }
  light.x = World.mouseX;
  light.y = World.mouseY;
  if (keyWentDown("left")) {
    leftroom();
    if ((runner.x) <= -90) {
      dead.visible = 100;
      score = "N̵̵͔̮͓̝̞͔̮͉̹͎̣̻̂̅͛ͪ́ͫͧ̒̈́̐̓ͩ̅ͫ̊͂ͫ̈́͜͝͞ͅo̢͉ͪ̿̌ͪ̓̆̌ͧ͜͜͜t̸̡̛͍̱͔̗̖͍̖͖͚͕͍͉ͤͮͬ͑̏͐ g̱̫̰̬̻̎́̍͂̋ͥ͜͞͠oo̶̢̡̻̼͍ͩ̾̇̆͆́ͬ͠͝d̛̯̹̤͈ͬ̎̈́̿ e̸͚̠̤͉̮̺̯̬ͪ̇ͭ̀̇͂͒̔̾̑ͯ̕̚͢n̸̩̹͇͕͚̝̞͙͍̭͎ͬ͌̀͌͛͐ͮ̋̓̈́ͥ͡o̴̡̧̨̡̦̬̘͎̗̩̪̬͙̅̿̋ͯͤͬ͋ͪ̉ͭ̐̊ͧ̂͘̚͢͜͡ͅư̴̵̧̡͎̭̥̞̙̤̩̻̩̗̜͎͇̮̙͙̤̟̼̓̌̀ͣ̉̆͒̓̽̈͌̎̀͌̄ͮ̈͌g̶̸̵̨̧̢͙̳̥̝̯̺̺͖̒́̑̆̀ͮͨ͌̆́̀̅̚̚͟_̴̷̞̗͆ͣ̓̀̓ͭ͘͢͞͞ͅh̷̻̹̱́̑͗͜";
      scorex = 25;
      scorey = 285;
    }
    if ((crawler.x) <= -25) {
      crawler.x = 400;
      crawler.velocityX = randomNumber(-5, -7);
    }
    runner.visible = 0;
    crawler.visible = 100;
    crawler.velocityX = randomNumber(-5, -7);
  }
  if (keyWentDown("right")) {
    rightroom();
    if ((runner.x) <= -90) {
      dead.visible = 100;
      score = "N̵̵͔̮͓̝̞͔̮͉̹͎̣̻̂̅͛ͪ́ͫͧ̒̈́̐̓ͩ̅ͫ̊͂ͫ̈́͜͝͞ͅo̢͉ͪ̿̌ͪ̓̆̌ͧ͜͜͜t̸̡̛͍̱͔̗̖͍̖͖͚͕͍͉ͤͮͬ͑̏͐ g̱̫̰̬̻̎́̍͂̋ͥ͜͞͠oo̶̢̡̻̼͍ͩ̾̇̆͆́ͬ͠͝d̛̯̹̤͈ͬ̎̈́̿ e̸͚̠̤͉̮̺̯̬ͪ̇ͭ̀̇͂͒̔̾̑ͯ̕̚͢n̸̩̹͇͕͚̝̞͙͍̭͎ͬ͌̀͌͛͐ͮ̋̓̈́ͥ͡o̴̡̧̨̡̦̬̘͎̗̩̪̬͙̅̿̋ͯͤͬ͋ͪ̉ͭ̐̊ͧ̂͘̚͢͜͡ͅư̴̵̧̡͎̭̥̞̙̤̩̻̩̗̜͎͇̮̙͙̤̟̼̓̌̀ͣ̉̆͒̓̽̈͌̎̀͌̄ͮ̈͌g̶̸̵̨̧̢͙̳̥̝̯̺̺͖̒́̑̆̀ͮͨ͌̆́̀̅̚̚͟_̴̷̞̗͆ͣ̓̀̓ͭ͘͢͞͞ͅh̷̻̹̱́̑͗͜";
      scorex = 25;
      scorey = 285;
    }
    if ((crawler.x) <= -25) {
      crawler.x = 400;
      crawler.velocityX = randomNumber(-5, -7);
    }
    runner.visible = 0;
    crawler.visible = 100;
    crawler.velocityX = randomNumber(-5, -7);
  }
  if (keyWentDown("up")) {
    frontroom();
    runner.x = 400;
    runner.visible = 100;
    runner.velocityX = randomNumber(-4, 10);
    if ((runner.x) <= -25) {
      runner.x = 400;
      runner.velocityX = randomNumber(-4, -6);
    }
    if ((crawler.x) <= -90) {
      dead.visible = 100;
      score = "N̵̵͔̮͓̝̞͔̮͉̹͎̣̻̂̅͛ͪ́ͫͧ̒̈́̐̓ͩ̅ͫ̊͂ͫ̈́͜͝͞ͅo̢͉ͪ̿̌ͪ̓̆̌ͧ͜͜͜t̸̡̛͍̱͔̗̖͍̖͖͚͕͍͉ͤͮͬ͑̏͐ g̱̫̰̬̻̎́̍͂̋ͥ͜͞͠oo̶̢̡̻̼͍ͩ̾̇̆͆́ͬ͠͝d̛̯̹̤͈ͬ̎̈́̿ e̸͚̠̤͉̮̺̯̬ͪ̇ͭ̀̇͂͒̔̾̑ͯ̕̚͢n̸̩̹͇͕͚̝̞͙͍̭͎ͬ͌̀͌͛͐ͮ̋̓̈́ͥ͡o̴̡̧̨̡̦̬̘͎̗̩̪̬͙̅̿̋ͯͤͬ͋ͪ̉ͭ̐̊ͧ̂͘̚͢͜͡ͅư̴̵̧̡͎̭̥̞̙̤̩̻̩̗̜͎͇̮̙͙̤̟̼̓̌̀ͣ̉̆͒̓̽̈͌̎̀͌̄ͮ̈͌g̶̸̵̨̧̢͙̳̥̝̯̺̺͖̒́̑̆̀ͮͨ͌̆́̀̅̚̚͟_̴̷̞̗͆ͣ̓̀̓ͭ͘͢͞͞ͅh̷̻̹̱́̑͗͜";
      scorex = 25;
      scorey = 285;
    }
    crawler.visible = 0;
  }
  if (mousePressedOver(runner)) {
    runner.x = 600;
    score = score + 1;
  }
  if (mousePressedOver(crawler)) {
    crawler.x = 600;
    score = score + 3;
  }

  // update sprites

  drawSprites();
  fill("white");
  textSize(36);
  text(score, scorex, scorey);
  fill("black");
  if (200 <= (World.mouseX)) {
    rect(0, 245, 75, 100);
  }
  if ((World.mouseY) <= 150) {
    rect(0, 245, 75, 100);
  }
}

// Create your functions here
